#nullable enable // autogenerated

using MVZ2Logic.Definitions;
using MVZ2Logic.Resources;
using PVZEngine.Base;
using UnityEngine;

namespace MVZ2Logic.Armors
{
    public class ArmorSlotDefinition : Definition
    {
        public ArmorSlotDefinition(string nsp, string name, string anchor) : base(nsp, name)
        {
            Anchor = anchor;
        }
        public string Anchor { get; set; }
        public Color HPBarColor { get; set; }
        public SpriteReference? HPBarIcon { get; set; }
        public override string GetDefinitionType() => LogicDefinitionTypes.ARMOR_SLOT;
    }
}
